// AUDIT SEUL — CONV-B isolé (sous-workflow)
// Entrée depuis Webhook POST : { wp_id, rapport_md (string), result_json (object) }
// result_json = contenu du _result.json (équivalent de result_data dans le pipeline principal)
// NOEUD 6b-AUDIT -- CONV-B Audit Final C1-C5 (POST-REDACTION)
// Guide Survie Etape 5 : CONV-B verifie le WP redige par CONV-A
// Distinct du codage CCI (deja fait en N8a)
"use strict";
const https = require("https");
const data   = $input.item.json;
const wp_id  = data.wp_id;
const ANTHROPIC_API_KEY = $env.ANTHROPIC_API_KEY;

const rapport_md    = data.rapport_md   || "";
const result_data   = data.result_json || data.result_data || {};
const sim           = result_data.simulation || {};
const stress_n2_audit = (result_data.stress_n2 || []).length > 0
  ? (result_data.stress_n2 || []).map(s => `  - ${s.label}: ${s.traj}`).join("\n")
  : "Non calculé";
const traj_attendue = result_data.meta?.trajectoire_attendue || "?";

const SYSTEM = `Tu es CONV-B, l'Auditeur Scientifique MEPA V6.2.
Tu audites le WP redige par CONV-A. Checklist obligatoire C1-C5.

[C1] CONFORMITE NUMERIQUE : t_b, dC_rel, dI_rel, FR_max dans le texte 
     correspondent exactement aux valeurs du _result.json ?
[C2] NOMENCLATURE : aucun "g" isole, "gamma"->JSON uniquement, γ(U+03B3)->texte redactionnel, labels D4 exacts ?
[C3] COHERENCE CONV-E : le WP utilise les valeurs codées par CONV-E (mepa_full_vars) ?
     Vérifier cohérence entre valeurs citées dans le rapport et variables_codees CONV-E.
     NOTE : CCI=null est normal si CONV-B CCI ne s'est pas déclenché — ne pas pénaliser.
[C4] NARRATIVE SMOOTHING (§4.3 Manuel Gouvernance) :
     La divergence traj_diagn != attendue est-elle documentée selon le format §4.3 ?
     Format CORRECT : "Divergence documentée — simulation produit (X) au lieu de (Y).
       [Condition technique : F<R toute simulation / t_bascule=null / etc.].
       Potentielle zone de réfutation."
     SMOOTHING DÉTECTÉ si : justification a posteriori par l'histoire
       ("ce résultat est cohérent avec [fait historique]") OU
       phrase expliquant POURQUOI la simulation a raison malgré la divergence.
     NOTE : l'explication historique est AUTORISÉE en S6/S7 — pas en S2.
[C5] COHERENCE STRESS-TESTS (référence : _result.json champs stress_n1 et stress_n2) :
     - Les trajectoires stress N1 (optimiste/pessimiste) dans S4 correspondent aux valeurs
       de stress_n1 dans _result.json ?
     - Les 8 combinaisons stress N2 documentées dans S4 correspondent aux valeurs
       de stress_n2 dans _result.json (données runner Python ci-dessous) ?
     - Le verdict ROBUSTE/METASTABLE dans S4 est cohérent avec verdict.robustesse ?
     NOTE PROTOCOLE : la source de référence pour C5 est _result.json (runner Python),
     pas le Nœud 12 du pipeline. Les stress N2 runner sont fournis ci-dessous.
     C5 = ANOMALIE si les trajectoires citées dans S4 divergent des valeurs runner,
     ou si S4 omet totalement de documenter les stress-tests disponibles.

VERDICT : CERTIFIE / REVISION_MINEURE / REVISION_MAJEURE / REJET
CERTIFIE = 5/5 ou anomalies mineures non bloquantes
REVISION_MINEURE = 1-2 anomalies C1/C2/C5 corrigeables sans re-simulation
REVISION_MAJEURE = anomalie C4 (narrative smoothing) OU anomalie C1 valeur cle
REJET = anomalie C1 trajectoire OU 3+ anomalies OU CCI<0.50

Reponds UNIQUEMENT en JSON pur sans markdown.`;

const USER = `WP: ${wp_id}
Trajectoire attendue : ${traj_attendue}
Trajectoire simulee : ${sim.traj || "?"}
FR_max : ${sim.FR_max || "?"} | t_bascule : ${sim.t_bascule ?? "null"}
dC_rel : ${sim.dC_rel ?? "null"} | dI_rel : ${sim.dI_rel ?? "null"}

STRESS-TESTS N2 (depuis runner — référence pour contrôle C5) :
${stress_n2_audit}

RAPPORT CONV-A (extrait):
${rapport_md}

Format:
{
  "wp_id": "${wp_id}",
  "audit_c1_c5": {
    "C1": {"statut": "OK|ANOMALIE", "anomalies": [], "detail": "..."},
    "C2": {"statut": "OK|ANOMALIE", "anomalies": [], "detail": "..."},
    "C3": {"statut": "OK|ANOMALIE", "anomalies": [], "detail": "..."},
    "C4": {"statut": "OK|ANOMALIE", "anomalies": [], "detail": "..."},
    "C5": {"statut": "OK|ANOMALIE", "anomalies": [], "detail": "..."}
  },
  "score_checklist": 0,
  "verdict": "CERTIFIE|REVISION_MINEURE|REVISION_MAJEURE|REJET",
  "instructions_revision": [],
  "anomalies": []
}`;

const payload = JSON.stringify({
  model: "claude-sonnet-4-6", max_tokens: 4000,
  system: [{ type: "text", text: SYSTEM, cache_control: { type: "ephemeral" } }], messages: [{ role: "user", content: USER }]
});

let audit_result = null;
let audit_error  = null;
try {
  audit_result = await new Promise((resolve, reject) => {
    const req = https.request({
      hostname: "api.anthropic.com", path: "/v1/messages", method: "POST",
      headers: { "Content-Type": "application/json",
        "x-api-key": ANTHROPIC_API_KEY,
        "anthropic-version": "2023-06-01",
        "anthropic-beta": "prompt-caching-2024-07-31" }
    }, (res) => {
      let body = "";
      res.on("data", c => body += c);
      res.on("end", () => {
      try {
        if (res.statusCode !== 200) { reject(new Error(`HTTP ${res.statusCode}: ${body.slice(0,200)}`)); return; }
          const t = JSON.parse(body).content?.[0]?.text || "{}";
          resolve(JSON.parse(t.replace(/```json|```/g,"").trim()));
        } catch(e) { reject(e); }
      });
    });
    req.setTimeout(90000, () => { req.destroy(); reject(new Error("Timeout 90s")); });
  req.on("error", reject);
    req.write(payload); req.end();
  });
} catch(e) { audit_error = e.message; }

const verdict = audit_result?.verdict || "NON_CALCULE";
const need_revision = verdict === "REVISION_MINEURE" || verdict === "REVISION_MAJEURE";

return {
  json: {
    ...data,
    audit_conv_b: audit_result,
    verdict_conv_b: verdict,
    score_checklist: audit_result?.score_checklist || 0,
    anomalies_conv_b: audit_result?.anomalies || [],
    instructions_revision: audit_result?.instructions_revision || [],
    need_revision,
    audit_error,
    message: `CONV-B audit: ${verdict} -- ${audit_result?.score_checklist || "?"}/5`
  }
};
